from __future__ import annotations

import base64
import hashlib
import subprocess
import sys
import tempfile
import zlib
from pathlib import Path

PATCH_SHA256 = "bc3910b171cb7f9683817a26e48453ac989b7cdac5d2a1885e5e8fe63b64f6ed"
PATCH_ZLIB_BASE64 = ""


def main() -> None:
    if len(sys.argv) != 2:
        raise SystemExit("Kullanım: apply_overdue_calendar_fix.py <kaynak-kökü>")
    root = Path(sys.argv[1]).resolve()
    patch = zlib.decompress(base64.b64decode(PATCH_ZLIB_BASE64))
    actual = hashlib.sha256(patch).hexdigest()
    if actual != PATCH_SHA256:
        raise SystemExit(f"Patch SHA uyuşmuyor: {actual}")
    subprocess.run(["git", "init", "-q"], cwd=root, check=True)
    with tempfile.NamedTemporaryFile(suffix=".patch", delete=False) as handle:
        handle.write(patch)
        patch_path = Path(handle.name)
    try:
        subprocess.run(["git", "apply", "--whitespace=nowarn", str(patch_path)], cwd=root, check=True)
    finally:
        patch_path.unlink(missing_ok=True)
    print(f"Gecikme takvim patch uygulandı: {actual}")


if __name__ == "__main__":
    main()
